*/\n/* .products-section-subtitle{font-family:\'Noto Sans\', sans-serif;font-size:18px;color:#5b6b80;line-height:1.6} */\n/* @media (max-width:640px){.products-section-title,.integration-title,.why-title{font-size:32px}} */\n\n\n@media(prefers-reduced-motion:reduce){*{animation:none !important;transition:none !important}}\n\n.et_pb_section .product-card {\n            line-height: 25.6px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .product-card-link {\n            line-height: 22.4px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n/* === FAQ === */\n.et_pb_section:has(.metal-faq){padding:60px 0 !important;background:#f8fafc !important}\n.metal-faq{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.metal-faq p{padding-bottom:0;line-height:1.6}\n.et_pb_section .metal-faq h2{margin:0;padding:0;line-height:1.6}\n.metal-faq summary{-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){}\n/* === CTA: เพิ่มผลผลิต ลดของเสีย === */\n.mp-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.mp-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.mp-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.mp-cta-super-d{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.12;pointer-events:none;z-index:0}\n.mp-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:170px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.08;z-index:1;pointer-events:none}\n.mp-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.mp-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.mp-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .mp-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .mp-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .mp-cta-container p{padding-bottom:0 !important}\n\n.mp-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.mp-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.mp-cta-btn:hover::before{left:100%}\n.mp-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.mp-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.mp-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.mp-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.mp-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.mp-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .mp-cta-title{font-size:28px;margin-bottom:16px}\n  .mp-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .mp-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .mp-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.mp-cta-btn{transition:none !important}.mp-cta-btn::before{display:none}}\n\n.et_pb_section:has(.mp-related-section){background:#F5F7FA;padding:0}\n.mp-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.mp-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.mp-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px;max-width:1200px;margin:0 auto}\n.mp-related-card{display:block;padding:24px;background:#fff;border-radius:12px;text-decoration:none;border:1px solid #e5e7eb;transition:box-shadow 0.3s ease;color:#333;line-height:1.6}\n.mp-related-card:hover{box-shadow:0 8px 24px rgba(0,8,100,0.1)}\n.mp-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.mp-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.mp-related-card{transition:none}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metal Hero (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metal Hero (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metal Hero (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><style>\n.et_pb_section:has(.metal-hero-inner){background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%)!important;padding:140px 0 100px!important;position:relative;overflow:hidden}\n.metal-hero-inner{max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index:1;text-align:center}\n.metal-hero-inner h1{font-family:\'Noto Sans\',sans-serif!important;font-size:52px!important;font-weight:700!important;color:#fff!important;margin:0 0 20px 0!important;padding:0!important;line-height:1.15!important}\n.metal-hero-inner h1 span{color:#00AFF0!important}\n.metal-hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(0,175,240,0.2);border:1px solid rgba(0,175,240,0.3);padding:8px 20px;border-radius:50px;color:#7EC8F2;font-size:14px;font-weight:500;margin-bottom:24px}\n.metal-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px!important;color:rgba(255,255,255,0.85)!important;max-width:700px;margin:0 auto 50px;line-height:32px!important}\n.metal-hero-stats{display:flex;justify-content:center;gap:60px}\n.metal-hero-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:42px;font-weight:700;color:#00AFF0!important;line-height:67.2px!important}\n.metal-hero-stat-label{font-size:14px;color:rgba(255,255,255,0.85);margin-top:4px!important;line-height:22.4px!important}\n@media(max-width:1024px){.metal-hero-inner h1{font-size:40px!important}.metal-hero-stats{gap:40px}}\n@media(max-width:640px){.metal-hero-inner h1{font-size:32px!important}.metal-hero-subtitle{font-size:17px!important}.metal-hero-stats{flex-direction:column;gap:24px}.metal-hero-stat-value{font-size:36px}}\n</style>\n    <div class="dw-d-bg dw-d-bg--bottom dw-d-bg--particle" style="opacity: 0.15; min-height: 30vh; bottom: -10%;"></div>\n            <div class="metal-hero-inner" style="position: relative; z-index: 2;">\n                <div class="metal-hero-badge">\n                    <span>การแปรรูปโลหะและพลาสติก</span>\n                </div>\n                <h1>เพิ่มผลผลิต <span>ลดของเสีย</span></h1>\n                <p class="metal-hero-subtitle">การปั๊มขึ้นรูป การฉีดพลาสติก การหล่อแบบ การกลึง CNC (ควบคุมด้วยคอมพิวเตอร์) การผลิตแบบกระบวนการที่รอบเวลาและอัตราผลผลิตขับเคลื่อนกำไรของคุณ</p>\n                <div class="metal-hero-stats">\n                    <div class="metal-hero-stat">\n                        <div class="metal-hero-stat-value">+15%</div>\n                        <div class="metal-hero-stat-label">อัตราผลผลิตที่เพิ่มขึ้นโดยเฉลี่ย</div>\n                    </div>\n                    <div class="metal-hero-stat">\n                        <div class="metal-hero-stat-value">-30%</div>\n                        <div class="metal-hero-stat-label">เวลาหยุดเครื่องโดยไม่ได้วางแผน</div>\n                    </div>\n                    <div class="metal-hero-stat">\n                        <div class="metal-hero-stat-value">100%</div>\n                        <div class="metal-hero-stat-label">มองเห็นรอบเวลาการผลิต</div>\n                    </div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="context-inner">\n                <h2>จุดสร้างกำไรอยู่ตรงนี้</h2>\n                <p>ในการแปรรูปโลหะและพลาสติก <strong>ต้นทุนวัสดุคิดเป็น 50-70% ของต้นทุนทั้งหมด</strong> ชิ้นงานเสียทุกชิ้นคือเงินที่ทิ้งลงถังขยะ ทุกวินาทีที่รอบเวลาเบี่ยงเบนคือกำลังการผลิตที่ไม่มีวันได้คืน การปรับปรุงเล็กๆ ในอัตราผลผลิตและประสิทธิภาพ <strong>ส่งผลตรงต่อกำไรสุทธิ</strong>— แต่คุณปรับปรุงสิ่งที่วัดไม่ได้ ไม่ได้</p>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="challenges-inner" style="position: relative; z-index: 2;">\n                <div class="challenges-header">\n                    <h2>ความท้าทายของการผลิตแบบกระบวนการ</h2>\n                    <p>การสูญเสียที่ซ่อนอยู่ กัดกร่อนกำไรของคุณ</p>\n                </div>\n                <div class="challenges-grid">\n                    <div class="challenge-card">\n                        <div class="challenge-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><polyline points="3 6 5 6 6 6"/><path d="M6 6v14a2 2 0 0 0 2 2h8a2 2 0 0 0 2-2V6"/><path d="M19 6h-1a2 2 0 0 0-2-2H8a2 2 0 0 0-2 2H5"/><line x1="10" y1="11" x2="10" y2="17"/><line x1="14" y1="11" x2="14" y2="17"/></svg>\n                        </div>\n                        <h3>ของเสียกินกำไร</h3>\n                        <p>ต้นทุนวัสดุเป็นค่าใช้จ่ายหลักของคุณ ชิ้นงานเสียทุกชิ้นคือเงินที่โยนทิ้ง การปรับปรุงอัตราผลผลิตเพียงเล็กน้อยสร้างผลกระทบต่อกำไรอย่างมีนัยสำคัญ</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"/></svg>\n                        </div>\n                        <h3>ปริศนาแม่พิมพ์</h3>\n                        <p>แม่พิมพ์ตัวไหนทำให้เกิดข้อบกพร่อง? เมื่อไหร่แม่พิมพ์ต้องซ่อมบำรุง? ถ้าไม่มีข้อมูล คุณก็แค่เดาจนกว่ามันจะพังอย่างหนัก</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n                        </div>\n                        <h3>รอบเวลาเบี่ยงเบน</h3>\n                        <p>เครื่องจักรช้าลงทีละน้อย พนักงานไม่ทันสังเกต 0.5 วินาทีต่อรอบ — แต่ตลอดกะทำงาน นั่นคือกำลังการผลิตที่สูญเสียจริงๆ</p>\n                    </div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <rect x="150" y="250" width="250" height="180" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.12"/>\n                    <rect x="200" y="290" width="150" height="100" rx="12" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/>\n                    <text x="275" y="345" font-family="\'Noto Sans\',sans-serif" font-size="10" font-weight="600" fill="#000864" opacity="0.08" text-anchor="middle">MOLD CAVITY</text>\n                    <line x1="150" y1="340" x2="100" y2="340" stroke="#000864" stroke-width="1" opacity="0.1"/>\n                    <line x1="100" y1="310" x2="100" y2="370" stroke="#000864" stroke-width="1" opacity="0.1"/>\n                    <text x="75" y="345" font-family="\'Noto Sans\',sans-serif" font-size="8" fill="#000864" opacity="0.08" text-anchor="middle">180mm</text>\n                    <path d="M400 340 L550 340" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="545,335 560,340 545,345" fill="#000864" opacity="0.12"/>\n                    <rect x="560" y="280" width="150" height="120" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.12"/>\n                    <path d="M580 310 L690 310 L690 370 L580 370" stroke="#000864" stroke-width="1" fill="none" opacity="0.1" stroke-dasharray="4 3"/>\n                    <text x="635" y="345" font-family="\'Noto Sans\',sans-serif" font-size="9" font-weight="600" fill="#000864" opacity="0.08" text-anchor="middle">PRESS</text>\n                    <path d="M635 280 L635 250" stroke="#000864" stroke-width="2" opacity="0.12"/>\n                    <path d="M625 260 L635 245 L645 260" stroke="#000864" stroke-width="2" fill="none" opacity="0.12"/>\n                    <path d="M710 340 L850 340" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <polygon points="845,335 860,340 845,345" fill="#000864" opacity="0.1"/>\n                    <rect x="860" y="300" width="100" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.12"/>\n                    <text x="910" y="345" font-family="\'Noto Sans\',sans-serif" font-size="9" font-weight="600" fill="#000864" opacity="0.08" text-anchor="middle">TRIM</text>\n                    <circle cx="1100" cy="350" r="60" stroke="#000864" stroke-width="2" fill="none" opacity="0.1"/>\n                    <circle cx="1100" cy="350" r="25" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <rect x="1090" y="322" width="20" height="12" rx="2" fill="#000864" opacity="0.08"/>\n                    <rect x="1090" y="362" width="20" height="12" rx="2" fill="#000864" opacity="0.08"/>\n                    <rect x="1070" y="340" width="12" height="20" rx="2" fill="#000864" opacity="0.08"/>\n                    <rect x="1118" y="340" width="12" height="20" rx="2" fill="#000864" opacity="0.08"/>\n                    <path d="M300 600 L500 600" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <path d="M600 600 L800 600" stroke="#000864" stroke-width="1.5" stroke-dasharray="6 4" opacity="0.08"/>\n                    <circle cx="450" cy="700" r="3" fill="#000864" opacity="0.08"/>\n                    <circle cx="900" cy="600" r="4" fill="#00AFF0" opacity="0.08"/>\n                    <circle cx="1250" cy="500" r="3" fill="#000864" opacity="0.06"/>\n                </svg>\n            </div>\n            <div class="solutions-inner" style="position: relative; z-index: 2;">\n                <div class="solutions-header">\n                    <h2>DigiWin แก้ปัญหาอย่างไร</h2>\n                    <p>ข้อมูลที่มองเห็นได้สำหรับการผลิตแบบกระบวนการ</p>\n                </div>\n                <div class="solutions-grid">\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M18 20V10"/><path d="M12 20V4"/><path d="M6 20v-6"/></svg>\n                        </div>\n                        <h3>ติดตามพารามิเตอร์กระบวนการ</h3>\n                        <p>เก็บข้อมูลอุณหภูมิ แรงดัน ความเร็ว จากทุกรอบ เชื่อมโยงพารามิเตอร์กับผลลัพธ์คุณภาพ</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>เก็บข้อมูลพารามิเตอร์แบบ Real-time</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>วิเคราะห์ความสัมพันธ์ด้านคุณภาพ</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>แจ้งเตือนเมื่อค่าเกินมาตรฐาน</span>\n                            </div></div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"/></svg>\n                        </div>\n                        <h3>จัดการแม่พิมพ์</h3>\n                        <p>ติดตามจำนวนช็อต ประวัติซ่อมบำรุง และประสิทธิภาพของเครื่องมือ คาดการณ์ความต้องการซ่อมบำรุงก่อนเกิดปัญหา</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ติดตามจำนวนช็อต</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>จัดตารางซ่อมบำรุง</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>แนวโน้มประสิทธิภาพเครื่องมือ</span>\n                            </div></div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>\n                        </div>\n                        <h3>วิเคราะห์ของเสีย</h3>\n                        <p>จัดหมวดหมู่ข้อบกพร่องตามประเภท เชื่อมโยงกับเครื่องจักร กะ ล็อตวัสดุ ค้นหาสาเหตุรากฐาน ไม่ใช่แค่อาการ</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>จัดหมวดหมู่ข้อบกพร่อง</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>วิเคราะห์ Pareto</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>เชื่อมโยงหาสาเหตุรากฐาน</span>\n                            </div></div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/></svg>\n                        </div>\n                        <h3>ปรับปรุงรอบเวลาการผลิต</h3>\n                        <p>ติดตามรอบเวลาแบบ Real-time เทียบกับมาตรฐาน แจ้งเตือนเมื่อเบี่ยงเบนและระบุคอขวด</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ตรวจจับรอบอัตโนมัติ</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>แจ้งเตือนเมื่อเบี่ยงเบน</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>คำนวณ OEE (ประสิทธิผลโดยรวมของเครื่องจักร)</span>\n                            </div></div>\n                    </div>\n\n                    <div class="solution-card" style="border: 2px solid rgba(0,175,240,0.3); background: linear-gradient(135deg, rgba(0,175,240,0.03), rgba(255,255,255,1));">\n                        <div class="solution-icon" style="background: linear-gradient(135deg, rgba(0,175,240,0.2), rgba(0,175,240,0.1));">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><path d="M9 12l2 2 4-4"/></svg>\n                        </div>\n                        <h3>รองรับ BOI</h3>\n                        <p>การกระทบยอดวัสดุระดับใบสั่งผลิตสำหรับการตรวจสอบ BOI (สำนักงานคณะกรรมการส่งเสริมการลงทุน) ติดตามการใช้วัสดุจริงต่อรอบการหล่อ — จำเป็นสำหรับการติดตามผลิตภัณฑ์ร่วมและแม่พิมพ์หลายช่อง</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>รายงานพร้อมตรวจสอบ BOI</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>จัดสรรต้นทุนผลิตภัณฑ์ร่วม</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>พิสูจน์แล้ว: ประหยัด 10 ล้านบาท+/ปี</span>\n                            </div></div>\n                    </div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Specialized ERP (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Specialized ERP (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Specialized ERP (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="spec-erp-inner" style="position: relative; z-index: 2;">\n                <div class="spec-erp-header">\n                    <h2>ทำไมโรงงานโลหะและพลาสติกต้องการ ERP เฉพาะทาง</h2>\n                    <p>7 ความจริงในการผลิตที่ ERP (ระบบบริหารทรัพยากรองค์กร) ทั่วไปรับมือไม่ได้</p>\n                </div>\n                <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 24px;">\n                    <div class="solution-card fade-in" style="padding: 32px;">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M3 3h18v18H3z" fill="none" stroke="currentColor" stroke-width="1.5"/><path d="M12 3v18M3 12h18" stroke="currentColor" stroke-width="1.5" fill="none"/><text x="6" y="9" font-size="5" fill="currentColor" font-weight="700">KG</text><text x="14" y="17" font-size="5" fill="currentColor" font-weight="700">PC</text></svg>\n                        </div>\n                        <h3 style="font-size: 18px;">แปลงหน่วยคู่</h3>\n                        <p>ติดตามสินค้าคงคลังทั้ง กก. (วัตถุดิบ) และ ชิ้น (สินค้าสำเร็จรูป) พร้อมกัน — แปลงอัตโนมัติในทุกรายการ</p>\n                    </div>\n                    <div class="solution-card fade-in" style="padding: 32px;">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M4 12h4l2-8 4 16 2-8h4" stroke="currentColor" stroke-width="1.5" fill="none"/><circle cx="20" cy="12" r="2" stroke="currentColor" stroke-width="1.5" fill="none"/></svg>\n                        </div>\n                        <h3 style="font-size: 18px;">จ้างชุบแข็งภายนอก</h3>\n                        <p>จัดการขั้นตอนการประมวลผลภายนอกที่ชิ้นงานออกไปและกลับมา — ตรวจสอบย้อนกลับได้ครบตลอดวงจร</p>\n                    </div>\n                    <div class="solution-card fade-in" style="padding: 32px;">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="4" y="8" width="16" height="12" rx="2" stroke="currentColor" stroke-width="1.5" fill="none"/><path d="M8 8V6a4 4 0 018 0v2" stroke="currentColor" stroke-width="1.5" fill="none"/><path d="M8 14h8M8 17h5" stroke="currentColor" stroke-width="1.5" fill="none"/></svg>\n                        </div>\n                        <h3 style="font-size: 18px;">ติดตามเตาหลอมและล็อต</h3>\n                        <p>ตรวจสอบพารามิเตอร์เตาหลอม (อุณหภูมิ ระยะเวลา บรรยากาศ) เชื่อมโยงกับล็อตเฉพาะสำหรับใบรับรองคุณภาพ</p>\n                    </div>\n                    <div class="solution-card fade-in" style="padding: 32px;">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M14.7 6.3a1 1 0 000 1.4l1.6 1.6a1 1 0 001.4 0l3.77-3.77a6 6 0 01-7.94 7.94l-6.91 6.91a2.12 2.12 0 01-3-3l6.91-6.91a6 6 0 017.94-7.94l-3.76 3.76z" stroke="currentColor" stroke-width="1.5" fill="none"/></svg>\n                        </div>\n                        <h3 style="font-size: 18px;">จัดการแม่พิมพ์</h3>\n                        <p>ติดตามวงจรชีวิตแม่พิมพ์ — จำนวนการใช้งาน ตารางซ่อมบำรุง จัดสรรต้นทุนข้ามผลิตภัณฑ์</p>\n                    </div>\n                    <div class="solution-card fade-in" style="padding: 32px;">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2" stroke="currentColor" stroke-width="1.5" fill="none"/><path d="M6 7V5a2 2 0 012-2h8a2 2 0 012 2v2" stroke="currentColor" stroke-width="1.5" fill="none"/><path d="M12 11v4M10 13h4" stroke="currentColor" stroke-width="1.5" fill="none"/></svg>\n                        </div>\n                        <h3 style="font-size: 18px;">ควบคุมปริมาณบรรจุภัณฑ์</h3>\n                        <p>จัดการปริมาณมาตรฐานต่อบรรจุภัณฑ์เพื่อการดำเนินงานคลังสินค้าที่มีประสิทธิภาพและการจัดส่งที่แม่นยำ</p>\n                    </div>\n                    <div class="solution-card fade-in" style="padding: 32px;">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M4 17l4-4 4 4 4-8 4 4" stroke="currentColor" stroke-width="1.5" fill="none"/><circle cx="4" cy="17" r="1.5" fill="currentColor"/><circle cx="8" cy="13" r="1.5" fill="currentColor"/><circle cx="12" cy="17" r="1.5" fill="currentColor"/><circle cx="16" cy="9" r="1.5" fill="currentColor"/><circle cx="20" cy="13" r="1.5" fill="currentColor"/></svg>\n                        </div>\n                        <h3 style="font-size: 18px;">เส้นทางการผลิตหลายขั้นตอน</h3>\n                        <p>จัดการเส้นทางที่ซับซ้อนที่ชิ้นงานผ่านการปั๊ม ลบครีบ ชุบ และประกอบ ด้วยศูนย์ต้นทุนที่ต่างกัน</p>\n                    </div>\n                    <div class="solution-card fade-in" style="padding: 32px;">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2L2 7l10 5 10-5-10-5z" stroke="currentColor" stroke-width="1.5" fill="none"/><path d="M2 17l10 5 10-5" stroke="currentColor" stroke-width="1.5" fill="none"/><path d="M2 12l10 5 10-5" stroke="currentColor" stroke-width="1.5" fill="none"/></svg>\n                        </div>\n                        <h3 style="font-size: 18px;">จัดการของเสียและอัตราผลผลิต</h3>\n                        <p>ติดตามอัตราผลผลิตวัสดุต่อกระบวนการ คำนวณต้นทุนของเสียอัตโนมัติ และป้อนกลับเข้า BOM (รายการวัตถุดิบ) costing</p>\n                    </div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metal Case Study (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metal Case Study (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metal Case Study (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="metal-case-study">\n    <div class="dw-d-bg dw-d-bg--bottom dw-d-bg--particle" style="opacity: 0.1;"></div>\n            <div style="max-width: 1000px; margin: 0 auto; padding: 0 24px; position: relative; z-index: 2;">\n                <div style="text-align: center; margin-bottom: 48px;">\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 13px; letter-spacing: 0.1em; text-transform: uppercase; color: var(--dw-cyan, #00E6FF); display: inline-block; margin-bottom: 12px;">ผลลัพธ์ที่พิสูจน์แล้ว</span>\n                    <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 36px; font-weight: 700; color: #fff; margin: 0;">ผลงานของ DigiWin ในอุตสาหกรรมโลหะ</h2>\n                </div>\n                <div class="fade-in" style="background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.12); border-radius: 20px; padding: 48px; backdrop-filter: blur(8px);">\n                    <div style="display: flex; flex-wrap: wrap; gap: 40px; align-items: center;">\n                        <div style="flex: 1; min-width: 280px;">\n                            <span style="font-family: \'JetBrains Mono\', monospace; font-size: 12px; letter-spacing: 0.1em; text-transform: uppercase; color: var(--dw-blue, #00AFF0); display: inline-block; margin-bottom: 8px;">กรณีศึกษา</span>\n                            <h3 style="font-family: \'Noto Sans\', sans-serif; font-size: 26px; font-weight: 700; color: #fff; margin: 0 0 8px 0;">Ginfong Metal Stamping</h3>\n                            <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; color: rgba(255,255,255,0.75); margin: 0 0 24px 0; line-height: 1.6;">การปั๊มโลหะ / การผลิตชิ้นส่วนแม่นยำ</p>\n                            <div style="display: flex; gap: 32px; flex-wrap: wrap; margin-bottom: 24px;">\n                                <div>\n                                    <div style="font-family: \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 800; color: var(--dw-blue, #00AFF0); line-height: 1;">23% <span style="font-size: 20px; color: rgba(255,255,255,0.75);">เป็น</span> 34%</div>\n                                    <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: rgba(255,255,255,0.75); margin-top: 4px;">กำไรขั้นต้นที่เพิ่มขึ้น</div>\n                                </div>\n                                <div>\n                                    <div style="font-family: \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 800; color: var(--dw-blue, #00AFF0); line-height: 1;">+200%</div>\n                                    <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: rgba(255,255,255,0.75); margin-top: 4px;">การเติบโตของรายได้</div>\n                                </div>\n                            </div>\n                            <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; color: rgba(255,255,255,0.85); line-height: 1.7; margin: 0 0 16px 0; font-style: italic; border-left: 3px solid var(--dw-blue, #00AFF0); padding-left: 16px;">“ด้วยการมองเห็นต้นทุนต่อออเดอร์แบบ Real-time ทำให้ Ginfong เปลี่ยนจากโรงปั๊มกำไรต่ำ เป็นพันธมิตรด้านการผลิตแม่นยำ”</p>\n                            <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; color: rgba(255,255,255,0.75); margin: 0;"><strong style="color: rgba(255,255,255,0.9);">โซลูชัน:</strong> DigiWin ERP พร้อมระบบจัดการต้นทุนแบบบูรณาการ</p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Processes (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Processes (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Processes (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-d-bg dw-d-bg--corner-tl" style="opacity: 0.08;"></div>\n            <div class="processes-inner" style="position: relative; z-index: 2;">\n                <h3>ประเภทกระบวนการที่เรารองรับ</h3>\n                <div class="processes-logos">\n                    <div class="process-logo">การปั๊มขึ้นรูป</div>\n                    <div class="process-logo">การฉีดพลาสติก</div>\n                    <div class="process-logo">การหล่อแบบ</div>\n                    <div class="process-logo">การกลึง CNC</div>\n                    <div class="process-logo">การตีขึ้นรูป</div>\n                    <div class="process-logo">การรีดขึ้นรูป</div>\n                    <div class="process-logo">งานแผ่นโลหะ</div>\n                    <div class="process-logo">การเป่าขึ้นรูป</div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="products-inner">\n                <div class="products-header">\n                    <h2>ผลิตภัณฑ์แนะนำสำหรับโลหะและพลาสติก</h2>\n                </div>\n                <div class="products-grid">\n                    <a href="../products/aiot/" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/><circle cx="12" cy="12" r="3"/></svg>\n                        </div>\n                        <h3>AIoT</h3>\n                        <p>เชื่อมต่อเครื่องจักรสำหรับเครื่องปั๊ม เครื่องฉีดพลาสติก และเครื่อง CNC ติดตาม OEE แบบ Real-time และเก็บข้อมูลพารามิเตอร์กระบวนการ</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                    <a href="../products/mes/" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M6 7V5a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v2"/><circle cx="6" cy="12" r="1"/><circle cx="10" cy="12" r="1"/><circle cx="14" cy="12" r="1"/><circle cx="18" cy="12" r="1"/></svg>\n                        </div>\n                        <h3>MES</h3>\n                        <p>ติดตามการผลิต เก็บข้อมูลคุณภาพ วิเคราะห์ของเสีย และจัดการแม่พิมพ์สำหรับการผลิตแบบกระบวนการ</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                    <a href="../products/erp/" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/><path d="M9 21V9"/></svg>\n                        </div>\n                        <h3>iGP ERP</h3>\n                        <p>ERP ขนาดพอดีสำหรับการดำเนินงานโลหะและพลาสติก พร้อมความสามารถด้านสินค้าคงคลังและการคิดต้นทุนที่แข็งแกร่ง</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="metal-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">คำถามที่พบบ่อย</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">ระบบ ERP ที่ดีที่สุดสำหรับโรงงานปั๊มโลหะในประเทศไทยคืออะไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">DigiWin มีโซลูชัน ERP (ระบบบริหารทรัพยากรองค์กร) และ MES (ระบบบริหารการผลิต) ที่ออกแบบมาเฉพาะสำหรับสภาพแวดล้อมการปั๊มโลหะและการผลิตแบบกระบวนการ ระบบมีการติดตามพารามิเตอร์กระบวนการแบบ Real-time ที่เก็บข้อมูลอุณหภูมิ แรงดัน และความเร็วจากทุกรอบ แล้วเชื่อมโยงพารามิเตอร์เหล่านั้นกับผลลัพธ์ด้านคุณภาพโดยตรง สำหรับโรงงานปั๊มโลหะที่ต้นทุนวัสดุคิดเป็น 50-70% ของต้นทุนทั้งหมด แนวทางที่ขับเคลื่อนด้วยข้อมูลนี้ช่วยเพิ่มอัตราผลผลิตเฉลี่ย 15% และลดเวลาหยุดเครื่องโดยไม่ได้วางแผนลง 30%</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin ช่วยลดของเสียในการฉีดพลาสติกได้อย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">DigiWin ลดของเสียในการฉีดพลาสติกด้วยการติดตามอัตราผลผลิตแบบ Real-time ร่วมกับ SPC (การควบคุมกระบวนการทางสถิติ) ระบบจัดหมวดหมู่ข้อบกพร่องตามประเภทและเชื่อมโยงกับเครื่องจักร กะ และล็อตวัสดุเฉพาะ โดยใช้เครื่องมือวิเคราะห์ Pareto และหาสาเหตุรากฐาน แทนที่จะค้นพบปัญหาคุณภาพหลังเกิดเหตุ พนักงานจะได้รับแจ้งเตือนทันทีที่พารามิเตอร์กระบวนการเบี่ยงเบน ทำให้แก้ไขได้ทันที แนวทางนี้มุ่งแก้ที่สาเหตุรากฐาน ไม่ใช่แค่อาการ เปลี่ยนการปรับปรุงอัตราผลผลิตเล็กๆ เป็นผลกระทบต่อกำไรอย่างมีนัยสำคัญ</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin สามารถติดตามการซ่อมบำรุงแม่พิมพ์และจำนวนช็อตได้หรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">ได้ DigiWin มีโมดูลจัดการแม่พิมพ์ในตัวที่ติดตามจำนวนช็อต ประวัติซ่อมบำรุงครบถ้วน และแนวโน้มประสิทธิภาพของเครื่องมือทุกตัว ระบบคาดการณ์ความต้องการซ่อมบำรุงจากข้อมูลการใช้งาน จัดตารางซ่อมบำรุงเชิงป้องกันก่อนเกิดปัญหาร้ายแรง วิธีนี้ขจัดการเดาเรื่องว่าแม่พิมพ์ตัวไหนทำให้เกิดข้อบกพร่องและเมื่อไหร่ต้องซ่อมบำรุง แทนที่การซ่อมบำรุงแบบตั้งรับด้วยการจัดการประสิทธิภาพเครื่องมือที่ขับเคลื่อนด้วยข้อมูล</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin รองรับ BOI compliance สำหรับผู้ผลิตโลหะและพลาสติกหรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">รองรับ DigiWin มีการกระทบยอดวัสดุระดับใบสั่งผลิตที่ออกแบบมาเฉพาะสำหรับการตรวจสอบ BOI (สำนักงานคณะกรรมการส่งเสริมการลงทุน) ในการผลิตโลหะและพลาสติก ระบบติดตามการใช้วัสดุจริงต่อรอบการหล่อ ซึ่งจำเป็นสำหรับการติดตามผลิตภัณฑ์ร่วมและแม่พิมพ์หลายช่องที่ผู้ตรวจสอบ BOI ต้องการ ผู้ผลิตที่ใช้ DigiWin สำหรับ BOI compliance ได้รับรายงานพร้อมตรวจสอบ BOI การจัดสรรต้นทุนผลิตภัณฑ์ร่วมที่แม่นยำ และประหยัดได้มากกว่า 10 ล้านบาทต่อปี</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin รองรับกระบวนการผลิตประเภทใดบ้าง?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">DigiWin รองรับกระบวนการแปรรูปโลหะและพลาสติกครบถ้วน รวมถึงการปั๊มขึ้นรูป การฉีดพลาสติก การหล่อแบบ การกลึง CNC การตีขึ้นรูป การรีดขึ้นรูป งานแผ่นโลหะ และการเป่าขึ้นรูป แต่ละประเภทกระบวนการได้รับประโยชน์จากความสามารถหลักของ DigiWin ในการปรับปรุงรอบเวลา ติดตามพารามิเตอร์กระบวนการ วิเคราะห์ของเสีย และจัดการแม่พิมพ์ ระบบให้การมองเห็นรอบเวลา 100% พร้อมตรวจจับรอบอัตโนมัติ แจ้งเตือนเมื่อเบี่ยงเบน และคำนวณ OEE (ประสิทธิผลโดยรวมของเครื่องจักร) ไม่ว่าจะเป็นกระบวนการผลิตประเภทใด</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: เพิ่มผลผลิต ลดของเสีย"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: เพิ่มผลผลิต ลดของเสีย: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: เพิ่มผลผลิต ลดของเสีย: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mp-cta-section">\n    <div class="mp-cta-super-d" aria-hidden="true"></div>\n    <div class="mp-cta-wave-flow" aria-hidden="true"></div>\n    <div class="mp-cta-container">\n      <h2 class="mp-cta-title">เพิ่มผลผลิต ลดของเสีย</h2>\n      <p class="mp-cta-subtitle">ดูว่า DigiWin ช่วยผู้ผลิตแบบกระบวนการอย่างไร</p>\n      <div class="mp-cta-btn-row">\n        <a href="/th/demo/" class="mp-cta-btn mp-cta-btn--primary">ติดต่อเรา</a>\n        <a href="/industries.html" class="mp-cta-btn mp-cta-btn--ghost">ดูอุตสาหกรรมอื่นๆ</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.mp-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.mp-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.mp-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.mp-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="mp-related-section">\n    <h2 class="mp-related-heading">สำรวจโซลูชันที่เกี่ยวข้อง</h2>\n    <div class="mp-related-grid">\n      <a href="/industries/automotive/" class="mp-related-card">\n        <h3 class="mp-related-card-title">ยานยนต์</h3>\n        <p class="mp-related-card-desc">ERP และ MES ที่สร้างมาเฉพาะสำหรับผู้ผลิตชิ้นส่วนยานยนต์และ OEM suppliers</p>\n      </a>\n      <a href="/industries/electronics/" class="mp-related-card">\n        <h3 class="mp-related-card-title">อิเล็กทรอนิกส์</h3>\n        <p class="mp-related-card-desc">ซอฟต์แวร์การผลิตสำหรับประกอบอิเล็กทรอนิกส์, สาย SMT และตรวจสอบย้อนกลับชิ้นส่วน</p>\n      </a>\n      <a href="/products/erp/" class="mp-related-card">\n        <h3 class="mp-related-card-title">ERP</h3>\n        <p class="mp-related-card-desc">ERP การผลิตครบวงจร สำหรับโรงงานไทย — ตั้งแต่ BOM จนถึงบัญชีการเงินและ BOI compliance</p>\n      </a>\n      <a href="/products/mes/" class="mp-related-card">\n        <h3 class="mp-related-card-title">MES</h3>\n        <p class="mp-related-card-desc">ระบบปฏิบัติการผลิตแบบ Real-time — ติดตาม OEE, SPC และใบสั่งผลิตแบบไม่ใช้กระดาษ</p>\n      </a>\n      <a href="/products/wms/" class="mp-related-card">\n        <h3 class="mp-related-card-title">WMS</h3>\n        <p class="mp-related-card-desc">จัดการคลังสินค้าอัจฉริยะด้วยบาร์โค้ด/RFID — ตั้งแต่รับเข้าจนถึงจัดส่ง ตรวจสอบย้อนกลับได้ครบ</p>\n      </a>\n      <a href="/products/aiot/" class="mp-related-card">\n        <h3 class="mp-related-card-title">AIoT</h3>\n        <p class="mp-related-card-desc">เชื่อมต่อเครื่องจักรเข้า ERP โดยตรงด้วยเซ็นเซอร์ IoT, Edge Computing และ AI Analytics</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100784;

