INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100784, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === METAL HERO (S1) === */\n/* Divi generates .et_pb_section_0{background:transparent!important;padding:0!important} — must beat it */\n.et_pb_section:has(.metal-hero-inner){background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%) !important;padding:140px 0 100px !important;position:relative;overflow:hidden}\n/* Target .metal-hero-inner (the actual element in HTML), NOT .metal-hero (doesn\'t exist in Divi) */\n.metal-hero-inner{max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index:1;text-align:center;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.metal-hero-inner p{padding-bottom:0;line-height:1.6}\n.metal-hero-inner h1{font-family:\'Noto Sans\', sans-serif !important;font-size:52px !important;font-weight:700 !important;color:#fff !important;margin:0 0 20px 0 !important;padding:0 !important;line-height:1.15 !important}\n.metal-hero-inner h1 span{color:#00AFF0 !important}\n.metal-hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(0, 175, 240, 0.2);border:1px solid rgba(0, 175, 240, 0.3);padding:8px 20px;border-radius:50px;color:#7EC8F2;font-size:14px;font-weight:500;margin-bottom:24px}\n.metal-hero-subtitle{font-family:\'Noto Sans\', sans-serif;font-size:20px !important;color:rgba(255,255,255,0.85) !important;max-width:700px;margin:0 auto 50px;line-height:32px !important;-webkit-font-smoothing:auto !important}\n.metal-hero-stats{display:flex;justify-content:center;gap:60px}\n.metal-hero-stat{text-align:center}\n.metal-hero-stat-value{font-family:\'Noto Sans\', sans-serif;font-size:42px;font-weight:700;color:rgb(0, 175, 240) !important;line-height:67.2px !important;-webkit-font-smoothing:auto !important}\n.metal-hero-stat-label{font-size:14px;color:rgba(255,255,255,0.85);margin-top:4px !important;line-height:22.4px !important;-webkit-font-smoothing:auto !important}\n.dw-d-bg{position:absolute;top:auto;right:-10%;bottom:-20%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center bottom;background-size:contain;opacity:0.2;pointer-events:none;z-index:0}\n@media (max-width:1024px){.metal-hero-inner h1{font-size:40px !important}.metal-hero-stats{gap:40px}}\n@media (max-width:640px){.metal-hero-inner h1{font-size:32px !important}.metal-hero-subtitle{font-size:17px !important}.metal-hero-stats{flex-direction:column;gap:24px}.metal-hero-stat-value{font-size:36px}}\n\n@media(prefers-reduced-motion:reduce){*{animation:none !important;transition:none !important}}\n/* === CONTEXT (S2) === */\n/* Divi 5 section boilerplate (font-smoothing, p padding, heading resets) */\n/* Divi wrapper override */\n.et_pb_section:has(.context-inner){padding:100px 0 !important;background:#fff !important}\n.context-section{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.context-section p{padding-bottom:0;line-height:1.6}\n.et_pb_section .context-section h2{margin:0;padding:0;line-height:1.6}\n.context-inner{max-width:900px;margin:0 auto;padding:0 24px;text-align:center}\n.context-inner h2{font-family:\'Noto Sans\', sans-serif;font-size:36px !important;font-weight:700 !important;color:#000864 !important;margin-bottom:24px !important;line-height:1.6 !important}\n.context-inner p{font-size:18px;color:#5b6b80;line-height:1.8}\n.context-inner p strong{color:#000864}\n\n\n@media(prefers-reduced-motion:reduce){*{animation:none !important;transition:none !important}}\n/* === CHALLENGES (S3) === */\n/* Divi 5 section boilerplate (font-smoothing, p padding, heading resets) */\n/* Divi wrapper override */\n.et_pb_section:has(.challenges-inner){padding:100px 0 !important;background:#F5F7FA !important}\n.challenges-section{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.challenges-section p{padding-bottom:0;line-height:1.6}\n.et_pb_section .challenges-section h2,.et_pb_section .challenges-section h3{margin:0;padding:0;line-height:1.6}\n/* Hover states */\n.challenge-card:hover .challenge-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)}\n.challenge-card:hover .challenge-icon svg{stroke:#fff}\n.stakes-inner, .challenges-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.stakes-header, .challenges-header{text-align:center;margin-bottom:60px}\n.stakes-header h2, .challenges-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px !important;font-weight:700 !important;color:#000864 !important;margin-bottom:16px !important;line-height:1.6 !important}\n.stakes-header p, .challenges-header p{font-size:18px;color:#5b6b80}\n.stakes-grid, .challenges-grid{display:grid;grid-template-columns:repeat(3, 1fr);gap:32px}\n.stake-card, .challenge-card{background:linear-gradient(145deg, #fef2f2 0%, #fee2e2 100%);border:1px solid #fecaca;border-radius:20px;padding:40px 32px;text-align:center}\n.stake-icon, .challenge-icon{width:72px;height:72px;background:linear-gradient(135deg, #fee2e2, #fecaca);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 24px;transition:all 0.4s ease}\n.stake-icon svg, .challenge-icon svg{width:32px;height:32px;stroke:#b91c1c;stroke-width:1.5;fill:none}\n.stake-card h3, .challenge-card h3{font-family:\'Noto Sans\', sans-serif;font-size:22px;color:#991b1b;margin-bottom:16px}\n.stake-card p, .challenge-card p{font-size:15px;color:#b91c1c;line-height:1.7}\n@media (max-width:1024px){.stakes-grid, .challenges-grid{grid-template-columns:1fr}}\n@media (max-width:640px){.stake-card, .challenge-card{padding:32px 24px}}\n\n\n@media(prefers-reduced-motion:reduce){*{animation:none !important;transition:none !important}}\n/* === SOLUTIONS (S4) === */\n/* Divi 5 section boilerplate (font-smoothing, p padding, heading resets) */\n/* Divi wrapper override */\n.et_pb_section:has(.solutions-inner){padding:100px 0 !important;background:#fff !important;position:relative;overflow:hidden}\n.solutions-section{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px;position:relative;overflow:hidden}\n.solutions-section p{padding-bottom:0;line-height:1.6}\n.et_pb_section .solutions-section h2,.et_pb_section .solutions-section h3{margin:0;padding:0;line-height:1.6}\n/* Hover states */\n.solution-card:hover{border-color:#00AFF0;box-shadow:0 12px 40px rgba(0, 175, 240, 0.12)}\n.solution-card:hover .solution-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)}\n.solution-card:hover .solution-icon svg{stroke:#fff}\n/* REF: BASE RULES from styles.css (check against inline CSS above) */\n.dw-section-scene{position:absolute;inset:0;pointer-events:none;z-index:1;overflow:hidden}\n.dw-section-scene svg{width:100%;height:100%;opacity:0.20}\n/* fade-in: visible by default (no JS scroll observer in Divi) */\n.fade-in{opacity:1;transform:none}\n.solutions-section{padding:0;background:transparent}\n.solutions-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.solutions-header{text-align:center;margin-bottom:60px}\n.solutions-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px !important;font-weight:700 !important;color:#000864 !important;margin-bottom:16px !important;line-height:1.6 !important}\n.solutions-header p{font-size:18px;color:#5b6b80}\n.solutions-grid{display:grid;grid-templa